import React from "react";
import { useGitHubRepos } from "../hooks/useGitHubRepos";

const GitHubHighlights = () => {
  const { repos, loading } = useGitHubRepos("Unix69");

  if (loading) return <p>Loading repositories...</p>;

  return (
    <section className="highlights-container">
      <div className="highlight-category-card">
        <h2 className="highlight-category-title">Repositories</h2>
        <ul className="highlight-items-list">
          {repos.slice(0, 5).map((repo) => (
            <li key={repo.id}>
              <a href={repo.html_url} target="_blank" rel="noopener noreferrer">
                {repo.name} {repo.language ? `(${repo.language})` : ""}
              </a>
            </li>
          ))}
        </ul>
      </div>
    </section>
  );
};

export default GitHubHighlights;
